import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"页面设置说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Page/page-settings.md","filePath":"cn/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"cn/Page/page-settings.md"};function h(c,t,n,l,i,s){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="页面设置说明" tabindex="-1">页面设置说明 <a class="header-anchor" href="#页面设置说明" aria-label="Permalink to &quot;页面设置说明&quot;">​</a></h1><p>页面设置用于调整网站显示、上传页默认选项、背景图和管理端显示效果。</p><h2 id="全局设置" tabindex="-1">全局设置 <a class="header-anchor" href="#全局设置" aria-label="Permalink to &quot;全局设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>功能</th></tr></thead><tbody><tr><td>网站标题</td><td>浏览器标签页显示的标题。</td></tr><tr><td>网站图标</td><td>浏览器标签页的小图标地址。</td></tr><tr><td>图床名称</td><td>前台页面显示的图床名称。</td></tr><tr><td>图床Logo</td><td>前台页面显示的 Logo 图片地址。</td></tr><tr><td>Logo跳转链接</td><td>点击 Logo 或头像后打开的链接。</td></tr><tr><td>背景切换间隔</td><td>多张背景轮播的切换时间，单位为毫秒；<code>60000</code> 表示 60 秒。</td></tr><tr><td>背景图透明度</td><td>背景图显示透明度，范围 <code>0</code> 到 <code>1</code>；数值越小越淡。</td></tr><tr><td>默认URL前缀</td><td>生成图片链接时使用的前缀；留空时使用当前站点域名。</td></tr></tbody></table><h2 id="客户端设置" tabindex="-1">客户端设置 <a class="header-anchor" href="#客户端设置" aria-label="Permalink to &quot;客户端设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>功能</th></tr></thead><tbody><tr><td>公告</td><td>上传页顶部公告内容，支持填写 HTML。</td></tr><tr><td>默认上传渠道</td><td>上传页默认选中的上传渠道，也可以选择 Smart Dispatch 自动调度。</td></tr><tr><td>默认上传目录</td><td>上传页默认目录；例如 <code>/user/</code>，留空或 <code>/</code> 表示根目录。</td></tr><tr><td>默认命名方式</td><td>上传后文件名的默认生成方式，见下方说明。</td></tr><tr><td>默认转换WebP</td><td>上传前将图片转换为 WebP。</td></tr><tr><td>默认开启压缩</td><td>上传前在浏览器本地压缩图片。</td></tr><tr><td>默认压缩阈值</td><td>图片超过该大小时自动压缩，单位 MB。</td></tr><tr><td>默认期望大小</td><td>压缩后希望接近的文件大小，单位 MB。</td></tr><tr><td>登录页背景图</td><td>用户登录页背景图。</td></tr><tr><td>上传页背景图</td><td>上传页背景图。</td></tr><tr><td>页脚传送门链接</td><td>页脚传送门按钮打开的链接。</td></tr><tr><td>隐藏页脚</td><td>开启后隐藏前台页脚。</td></tr></tbody></table><h2 id="管理端设置" tabindex="-1">管理端设置 <a class="header-anchor" href="#管理端设置" aria-label="Permalink to &quot;管理端设置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>功能</th></tr></thead><tbody><tr><td>管理端登录页背景图</td><td>管理端登录页背景图。</td></tr><tr><td>管理端背景图</td><td>管理端后台页面背景图；可填单张图片 URL，也可填多个 URL。</td></tr><tr><td>图像加载模式</td><td>管理端图片列表的预览加载方式，可选择原图或智能加载；智能加载会优先给公开图片使用缩略图，受限图片使用原图。</td></tr><tr><td>缩略图图源</td><td>选择缩略图由哪个服务生成，可选 wsrv.nl、Cloudflare 图片转换或 WordPress Photon；选择 Cloudflare 图片转换时，需要先在 Cloudflare 开启图片转换功能。</td></tr><tr><td>Live2D 看板娘</td><td>开启后在管理端显示 Live2D 看板娘。</td></tr><tr><td>烟花点击特效</td><td>开启后点击页面时显示烟花效果。</td></tr><tr><td>星星拖尾特效</td><td>开启后鼠标移动时显示星星拖尾效果。</td></tr></tbody></table><h2 id="背景图填写方式" tabindex="-1">背景图填写方式 <a class="header-anchor" href="#背景图填写方式" aria-label="Permalink to &quot;背景图填写方式&quot;">​</a></h2><p>登录页背景图、上传页背景图、管理端登录页背景图支持以下写法：</p><table tabindex="0"><thead><tr><th>写法</th><th>效果</th></tr></thead><tbody><tr><td><code>bing</code></td><td>使用必应壁纸轮播。</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>多张图片轮播。</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>单张背景图。</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>随机图接口链接；也可以先在“其他设置”里配置自己的随机图 API，再把调用演示的随机图链接按单张背景图格式填到这里。</td></tr></tbody></table><p>管理端背景图支持填写图片 URL；多个 URL 可按页面提示用英文逗号分隔。留空时使用默认背景。</p><h2 id="默认命名方式" tabindex="-1">默认命名方式 <a class="header-anchor" href="#默认命名方式" aria-label="Permalink to &quot;默认命名方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>生成效果</th></tr></thead><tbody><tr><td>默认</td><td>时间随机前缀 + 原文件名，例如 <code>1760000000000_cat.png</code>。</td></tr><tr><td>仅前缀</td><td>只使用时间随机前缀和扩展名，例如 <code>1760000000000.png</code>。</td></tr><tr><td>仅原名</td><td>保留原文件名，例如 <code>cat.png</code>；重名时自动加 <code>(1)</code>、<code>(2)</code>。</td></tr><tr><td>短链接</td><td>使用 8 位短 ID 和扩展名，例如 <code>a1b2c3d4.png</code>。</td></tr></tbody></table>',14)])])}const u=d(o,[["render",h]]);export{p as __pageData,u as default};
